#include<stdio.h>
int main(){
    int n,m;
    scanf("%d%d",&n,&m);
    int count=0;
    for(int i=1;i<=n;i++){
        if(i%m==0){
            if(i>=(float)n/2 && i<=n){
            printf("%d",i);
            count++;
            break;
            }
        }
    }
    if(count==0)
        printf("-1");
}

