use std::cmp;

fn main() {
    let (n, m) = R!(usize, usize);
    let mut dp = vec![vec![n+1; m]; n+1];
    dp[0][0] = 0;
    for i in 0..n {
        for j in 0..m {
            dp[i+1][(j+1) % m] = cmp::min(dp[i+1][(j+1) % m], dp[i][j] + 1);
            if i + 2 <= n {
                dp[i+2][(j+1) % m] = cmp::min(dp[i+2][(j+1) % m], dp[i][j] + 1);
            }
        }
    }

    W!(if dp[n][0] <= n { dp[n][0] as i32 } else { -1 })
}
